import type { FlickClaudeSessionsRow } from "./chkit-types.js";
import { FlickClaudeSessionsRowSchema } from "./chkit-types.js";

export interface Ingestor {
	insert(params: {
		table: string;
		values: Record<string, unknown>[];
	}): Promise<void>;
}

export async function ingestFlickClaudeSessions(
	ingestor: Ingestor,
	rows: FlickClaudeSessionsRow[],
	options?: { validate?: boolean },
): Promise<void> {
	const data = options?.validate
		? rows.map((row) => FlickClaudeSessionsRowSchema.parse(row))
		: rows;
	await ingestor.insert({
		table: "flick.claude_sessions",
		values: data as unknown as Record<string, unknown>[],
	});
}

