 78→FROM system.tables
 79→WHERE is_temporary = 0
 80→  AND database NOT IN ('system', 'information_schema', 'INFORMATION_SCHEMA')`);
 81→            const out = [];
 82→            for (const row of rows) {
 83→                const kind = inferSchemaKindFromEngine(row.engine);
 84→                if (!kind)
 85→                    continue;
 86→                out.push({
 87→                    kind,
 88→                    database: row.database,
 89→                    name: row.name,
