106→FROM system.columns
107→WHERE database IN (${quotedDatabases})`);
108→            const indexes = await this.query(`SELECT database, table, name, expr, type, granularity
109→FROM system.data_skipping_indices
110→WHERE database IN (${quotedDatabases})`);
